// b = v├╜┼бka z├бkladn├нho p├нsmene (verz├бlky=112, minusky bez dotahu=81, s dotahem=112)
const DIACRITIC_INFO = {
  '├Б':{s:'┬┤',b:112},'├Й':{s:'┬┤',b:112},'├Н':{s:'┬┤',b:112},'├У':{s:'┬┤',b:112},'├Ъ':{s:'┬┤',b:112},'├Э':{s:'┬┤',b:112},'─╣':{s:'┬┤',b:112},'┼Ф':{s:'┬┤',b:112},'─Ж':{s:'┬┤',b:112},'┼Ъ':{s:'┬┤',b:112},'┼Г':{s:'┬┤',b:112},
  '├б':{s:'┬┤',b:81},'├й':{s:'┬┤',b:81},'├н':{s:'┬┤',b:81},'├│':{s:'┬┤',b:81},'├║':{s:'┬┤',b:81},'├╜':{s:'┬┤',b:81},'─║':{s:'┬┤',b:112},'┼Х':{s:'┬┤',b:81},'─З':{s:'┬┤',b:81},'┼Ы':{s:'┬┤',b:81},'┼Д':{s:'┬┤',b:81},
  '─М':{s:'╦З',b:112},'┼а':{s:'╦З',b:112},'┼╜':{s:'╦З',b:112},'┼Ш':{s:'╦З',b:112},'┼З':{s:'╦З',b:112},'┼д':{s:'╦З',b:112},
  '─Н':{s:'╦З',b:81},'┼б':{s:'╦З',b:81},'┼╛':{s:'╦З',b:81},'┼Щ':{s:'╦З',b:81},'┼И':{s:'╦З',b:81},
  '├Д':{s:'┬и',b:112},'├Ц':{s:'┬и',b:112},'├Ь':{s:'┬и',b:112},'├д':{s:'┬и',b:81},'├╢':{s:'┬и',b:81},'├╝':{s:'┬и',b:81},
  '┼о':{s:'┬░',b:112},'┼п':{s:'┬░',b:81},
  '├Ф':{s:'^',b:112},'├┤':{s:'^',b:81},
  '┼╗':{s:'┬╖',b:112},'┼╝':{s:'┬╖',b:81},
  '─Д':{s:'╦Ы',b:112,below:true},'─Ш':{s:'╦Ы',b:112,below:true},'─Е':{s:'╦Ы',b:81,below:true},'─Щ':{s:'╦Ы',b:81,below:true},
};

// V├╜┼бky nad/pod ├║─Нa┼Щ├нm p┼Щi h=112 (pouze nestandardn├н znaky; standard = [112, 0])
// [v├╜┼бka nad ├║─Нa┼Щ├нm, v├╜┼бka pod ├║─Нa┼Щ├нm] тАФ plat├н pro MIT i ENG (stejn├б osnova)
const CHAR_HEIGHTS = {"0":[113,1],"2":[113,0],"3":[113,1],"5":[112,1],"6":[112,1],"8":[113,1],"9":[113,0],"┼д":[142,0],"├Б":[142,0],"U":[112,1],"o":[81,1],"(":[120,8],"├Д":[136,0],"├Ъ":[142,1],"├│":[112,1],")":[120,8],"─Д":[112,32],"┼о":[150,1],"├╢":[112,1],"%":[113,1],"├Ь":[136,1],"├┤":[112,1],"+":[68,0],"C":[113,1],"p":[81,32],"─М":[142,1],"q":[81,32],"=":[66,0],"─Ж":[142,1],"r":[81,0],"-":[52,0],".":[16,0],"─О":[142,0],"├Э":[142,0],"s":[80,1],":":[66,0],"├Й":[142,0],"┼╜":[142,0],"┼б":[112,1],";":[44,12],"─Ъ":[142,0],"┼╣":[142,0],"┼Ы":[112,1],"тАЮ":[16,6],"─Ш":[112,32],"┼╗":[136,0],"t":[104,0],"a":[81,1],"G":[113,1],"├б":[112,1],"u":[80,1],"<":[80,0],"├д":[112,1],"├║":[112,1],">":[80,0],"─Е":[81,32],"┼п":[120,1],"├Н":[142,0],"b":[112,1],"├╝":[112,1],"J":[112,1],"c":[81,1],"v":[80,0],"─Н":[112,1],"w":[80,0],"─З":[112,1],"x":[80,0],"d":[112,1],"y":[80,32],"─╣":[142,0],"─П":[112,1],"├╜":[112,32],"e":[81,1],"z":[80,0],"├й":[112,1],"─Ы":[112,1],"┼З":[142,0],"─Щ":[81,32],"┼Г":[142,0],"├Я":[113,0],"O":[113,1],"g":[81,33],"├У":[142,1],"├Ц":[136,1],"├Ф":[142,1],"j":[112,32],"Q":[113,3],"┼Ш":[142,0],"┼Ф":[142,0],"─║":[142,0],"S":[113,1],"┼а":[142,1],"m":[81,0],"┼Ъ":[142,1],"n":[81,0],"?":[113,0]};

function calculateLine(text, fontType, height, compression) {
  const fd = FONT_DATA[fontType];
  if (!fd || !text) return null;
  const k = height / 112;
  const chars = [...text];
  const details = [];
  let totalAt112 = 0;
  let hasError = false, hasUndefined = false;
  let maxAbove112 = 112, maxBelow112 = 0;

  for (let i = 0; i < chars.length; i++) {
    const ch = chars[i];
    if (ch === " ") {
      const sw = fontType === "mit" ? Math.round((5/7)*112) : Math.round((4/7)*112);
      details.push({ type:"space", char:"тО╡", width:sw });
      totalAt112 += sw;
      continue;
    }
    const w = fd.widths[ch];
    if (w === undefined) { details.push({ type:"char", char:ch, width:null, error:true }); hasError=true; continue; }
    details.push({ type:"char", char:ch, width:w });
    totalAt112 += w;
    const hd = CHAR_HEIGHTS[ch] || [112, 0];
    maxAbove112 = Math.max(maxAbove112, hd[0]);
    maxBelow112 = Math.max(maxBelow112, hd[1]);
    if (i < chars.length - 1) {
      const ch2 = chars[i+1];
      if (ch2 === " ") continue;
      const kern = fd.kerning?.[ch]?.[ch2];
      if (kern !== undefined && kern !== null) {
        details.push({ type:"kern", char1:ch, char2:ch2, width:kern });
        totalAt112 += kern;
      } else {
        details.push({ type:"kern", char1:ch, char2:ch2, width:null, undefined:true });
        hasUndefined = true;
      }
    }
  }
  const lengthAt100 = totalAt112 * k;
  const lengthFinal = Math.round(lengthAt100 * compression / 100);
  const maxAbove = Math.round(maxAbove112 * k);
  const maxBelow = Math.round(maxBelow112 * k);
  return { details, totalAt112, k, lengthAt100, lengthFinal, compression, hasError, hasUndefined, text, maxAbove, maxBelow };
}

function calcMultiline(text, fontType, height, compression, lineGapE, padTopE, padBotE, padSideE) {
  const lines = text.split("\n").filter(l => l.length > 0);
  if (!lines.length) return null;
  const E = (1/7)*height;
  const lineGap = Math.round(lineGapE * E);
  const lineResults = lines.map(l => calculateLine(l, fontType, height, compression));
  const valid = lineResults.filter(Boolean);
  const maxW = Math.max(...valid.map(r => r.lengthFinal));
  const n = valid.length;
  const textH = n * height + (n-1) * lineGap;
  const diacTop = valid[0] ? Math.max(0, valid[0].maxAbove - height) : 0;
  const diacBot = valid[n-1] ? valid[n-1].maxBelow : 0;
  const textHActual = textH + diacTop + diacBot;
  const pT = Math.round(padTopE*E), pB = Math.round(padBotE*E), pS = Math.round(padSideE*E);
  return { lineResults, maxWidth:maxW, textBlockHeight:textH, textBlockHeightActual:textHActual,
    diacTop, diacBot, totalWidth:maxW+2*pS, totalHeight:textHActual+pT+pB,
    lineGap, E:Math.round(E), padTop:pT, padBottom:pB, padSide:pS, numLines:n, lineGapE, padTopE, padBotE, padSideE };
}

function findMinComp(text, fontType, height, maxW, padSideE) {
  const E=(1/7)*height, pS=Math.round(padSideE*E), maxTxt=maxW-2*pS;
  if(maxTxt<=0) return null;
  const lines=text.split("\n").filter(l=>l.length>0);
  let maxL=0;
  for(const l of lines){const r=calculateLine(l,fontType,height,100);if(r)maxL=Math.max(maxL,r.lengthAt100);}
  if(!maxL)return null;
  if(maxL<=maxTxt)return{compression:100,fits:true};
  const c=(maxTxt/maxL)*100;
  return c>=85?{compression:Math.ceil(c),fits:true}:{compression:Math.ceil(c),fits:false,needsNarrow:true};
}

